<?php require_once 'header.php';
$daily=$pdo->query('SELECT DATE(sale_date) d, SUM(total_amount) total, SUM(profit) profit FROM sales GROUP BY DATE(sale_date) ORDER BY d DESC LIMIT 30')->fetchAll();
$week=$pdo->query('SELECT YEARWEEK(sale_date) w, SUM(total_amount) total, SUM(profit) profit FROM sales GROUP BY YEARWEEK(sale_date) ORDER BY w DESC LIMIT 12')->fetchAll();
$month=$pdo->query('SELECT DATE_FORMAT(sale_date, "%Y-%m") m, SUM(total_amount) total, SUM(profit) profit FROM sales GROUP BY DATE_FORMAT(sale_date, "%Y-%m") ORDER BY m DESC LIMIT 12')->fetchAll();
$top=$pdo->query('SELECT p.name, SUM(si.quantity) qty, SUM(si.total) total FROM sale_items si JOIN products p ON p.id=si.product_id GROUP BY p.id ORDER BY qty DESC LIMIT 10')->fetchAll();
?>
<h1>Reports</h1><div class="report-grid"><div class="panel"><h2>Mauzo ya Siku</h2><table><tr><th>Date</th><th>Total</th><th>Faida</th></tr><?php foreach($daily as $r): ?><tr><td><?= e($r['d']) ?></td><td><?= money($r['total']) ?></td><td><?= money($r['profit']) ?></td></tr><?php endforeach; ?></table></div><div class="panel"><h2>Mauzo ya Wiki</h2><table><tr><th>Week</th><th>Total</th><th>Faida</th></tr><?php foreach($week as $r): ?><tr><td><?= e($r['w']) ?></td><td><?= money($r['total']) ?></td><td><?= money($r['profit']) ?></td></tr><?php endforeach; ?></table></div><div class="panel"><h2>Mauzo ya Mwezi</h2><table><tr><th>Month</th><th>Total</th><th>Faida</th></tr><?php foreach($month as $r): ?><tr><td><?= e($r['m']) ?></td><td><?= money($r['total']) ?></td><td><?= money($r['profit']) ?></td></tr><?php endforeach; ?></table></div><div class="panel"><h2>Bidhaa Zinazouzwa Zaidi</h2><table><tr><th>Product</th><th>Qty</th><th>Total</th></tr><?php foreach($top as $r): ?><tr><td><?= e($r['name']) ?></td><td><?= e($r['qty']) ?></td><td><?= money($r['total']) ?></td></tr><?php endforeach; ?></table></div></div>
<?php require_once 'footer.php'; ?>
